local success,err=pcall(function()Player:WaitForChild("PlayerGui")createGUI()Player.CharacterAdded:Connect(function()task.wait(0.5)if pageContainer then if currentPage=="home"then createHomePage(pageContainer)elseif currentPage=="player"then createPlayerPage(pageContainer)elseif currentPage=="exploit"then createExploitPage(pageContainer)elseif currentPage=="visual"then createVisualPage(pageContainer)elseif currentPage=="floor"then createFloorPage(pageContainer)elseif currentPage=="about"then createAboutPage(pageContainer)end end end)RunService.RenderStepped:Connect(function()local alive=isAlive()local char=getCharacter()local hrp=getRootPart()if not alive or not char or not hrp then return end if PLAYER_STATE.SpeedBoost then local humanoid=char:FindFirstChild("Humanoid")if humanoid then humanoid.WalkSpeed=PLAYER_STATE.SpeedValue end end if PLAYER_STATE.SpeedBoost and Floor and Floor.Value=="Mines"and char:GetAttribute("Climbing")then local humanoid=char:FindFirstChild("Humanoid")if humanoid then humanoid.WalkSpeed=PLAYER_STATE.SpeedValue+PLAYER_STATE.LadderSpeedValue end end if PLAYER_STATE.NoAcceleration then hrp.CustomPhysicalProperties=PhysicalProperties.new(100,0.5,0.2)local collision=char:FindFirstChild("Collision")if collision then collision.CustomPhysicalProperties=PhysicalProperties.new(100,0.5,0.2)end else hrp.CustomPhysicalProperties=PhysicalProperties.new(0.4,0.2,0.2)local collision=char:FindFirstChild("Collision")if collision then collision.CustomPhysicalProperties=PhysicalProperties.new(0.4,0.2,0.2)end end if PLAYER_STATE.Noclip then local collision=char:FindFirstChild("Collision")if collision then collision.CanCollide=false local crouch=collision:FindFirstChild("CollisionCrouch")if crouch then crouch.CanCollide=false end end local collisionPart=char:FindFirstChild("CollisionPart")if collisionPart then collisionPart.CanCollide=false end hrp.CanCollide=false end if PLAYER_STATE.AntiHear and RemoteFolder then local crouch=RemoteFolder:FindFirstChild("Crouch")if crouch then crouch:FireServer(true)end end if VISUAL_STATE.Fullbright then Lighting.Ambient=Color3.fromRGB(255,255,255)end if VISUAL_STATE.NoCameraShake and RequiredMainGame then RequiredMainGame.csgo=CFrame.new()end if PLAYER_STATE.SpamTools then for _,otherPlayer in ipairs(Players:GetPlayers())do if otherPlayer~=Player then if otherPlayer.Backpack then for _,tool in ipairs(otherPlayer.Backpack:GetChildren())do if tool:IsA("Tool")and tool.Name~="Candle"then local remote=tool:FindFirstChildWhichIsA("RemoteEvent")if remote then remote:FireServer()end end end end if otherPlayer.Character then local tool=otherPlayer.Character:FindFirstChildOfClass("Tool")if tool and tool.Name~="Candle"then local remote=tool:FindFirstChild("Remote")if remote then remote:FireServer()end end end end end end if PLAYER_STATE.AntiEyes and Workspace:FindFirstChild("Eyes")and RemoteFolder then local motor=RemoteFolder:FindFirstChild("MotorReplication")if motor then motor:FireServer(-890)end end UpdateAllESP()end)end)if not success then warn("垃圾中心 - Doors 加载失败: "..tostring(err))else print("👻 垃圾中心 - Doors v1.0.0 | 完整ESP/楼层功能")
end
